var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"어머, 우리 마을을 구해주신 분이군요.","JPN":"まあ、私たちの村を助けてくださった方ですね。","ENG":"Oh my... So you're the one who saved our village.","TWN":"天啊，你們就是拯救我們村子的恩人啊。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"마을을 대표해 감사드려요.","JPN":"村を代表して、お礼を申し上げます。","ENG":"On behalf of everyone here... truly, thank you.","TWN":"我代表村民謝謝你們。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"음?하,하핫이것참쑥쓰럽네나는그냥여기로오라그래서오라그런거니까너무신경쓰지마","JPN":"うん？　は、ははっ、なんだその照れくさいっていうかあたしはただここに行けって言われて来ただけだし気にすんなっていうか","ENG":"Uh? H-haha... that's, uh, really embarrassing, I-I only came because they said to come, so don't... don't mind it too much...","TWN":"欸？哈、哈哈不用放在心上只是叫我來我就來了啦"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네 엄니임다!","JPN":"モネの母ちゃんっす！","ENG":"Mone's mama is here!","TWN":"是莫妮的媽媽！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이, 이렇게 젊어 보이는 사람이 애 엄마라고……?","JPN":"こ、こんなに若く見えるのにこいつの母親だって……？","ENG":"Th-this young-looking lady is a mom...?","TWN":"看、看起來這麼年輕的人是孩子的媽媽……？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"엄니! 마을은 별일 없었슴까?!","JPN":"母ちゃん！　村は大丈夫だったっすか！？","ENG":"Mama! Is the village all right?!","TWN":"媽媽！村子沒事吧？！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그럼! 베로니카 씨와 다른 용병분들이 노력해 주신 덕분이야.","JPN":"もちろんよ！　ベロニカさんと他の傭兵の方々が頑張ってくださったおかげよ。","ENG":"Of course. Veronica and the other mercenaries also helped so much.","TWN":"當然啦！這都要多虧貝洛妮卡小姐和其他傭兵的幫忙。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"예전에는 마을에서 쫓아내겠다고 으르렁거리던 사람들이었는데…….","JPN":"昔は村から追い出すってすごんでいた人たちだったのに……","ENG":"To think those same people once talked about driving us out...","TWN":"是以前那些說要把我們趕出去的人……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"살다 보니 이런 일도 다 있네.","JPN":"こんなこともあるのね。","ENG":"But I suppose that's life, isn't it?","TWN":"果然活久了什麼事都會發生。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그 당시에도 마을 사람들을 쫓아내는 것에 거부감을 느끼던 분들이었습니다.","JPN":"当時も村の人を追い出すことに抵抗感を抱いていたようですよ。","ENG":"Even back then, they were uncomfortable with chasing out villagers.","TWN":"那時候也有不少人反對驅逐村民。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"<color=#ffd34c>마음의 빚을 갚으러 왔다.</color>라고 했던가요?","JPN":"<color=#ffd34c>心の借りを返すために来た</color>、でしたっけ？","ENG":"I believe they said they'd come to <color=#ffd34c>repay a debt of the heart</color>, wasn't it?","TWN":"說是來<color=#ffd34c>償還心中的債</color>嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"덕분에 마음 놓고 해변으로 나가 침식체를 소탕할 수 있었습니다.","JPN":"おかげで安心して海辺に行き、侵食体を相手することができました。","ENG":"Thanks to them, we were able to head to the beach and clear out the C.O.s without worry.","TWN":"多虧如此，我才能放心到海邊掃蕩侵蝕體。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"물론… 메이드장님이 안 계셨더라면 완전히 안심하지는 못했을 테지만요.","JPN":"もちろん……いざとなればメイド長がいる、という根拠もあったのですが。","ENG":"Though... without the Chief Maid, we wouldn't have felt completely safe.","TWN":"當然……若不是女僕長在，我們可能還是無法安心就是了。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저는 뒤에서 지원 사격을 해줬을 뿐이에요. 릴리.","JPN":"私は後ろで支援射撃をしていただけですよ、リリー。","ENG":"I was only providing covering fire from behind, Lily.","TWN":"我只是在後方支援射擊而已，莉莉。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"마을을 습격하는 침식체를 소탕한 건 전적으로 용병분들의 활약 덕입니다.","JPN":"村を襲撃する侵食体を掃討したのは、全面的に傭兵の皆さんが活躍してくださったおかげです。","ENG":"Clearing out the C.O.s attacking the village was entirely the mercenaries' achievement.","TWN":"真正掃蕩侵蝕體的是傭兵們的功勞。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"총알 한 발로 침식체 코어를 꿰뚫어 버리는 사람이 할 말은 아닌 것 같은데.","JPN":"銃弾一発で侵食体のコアを貫く人が言うことじゃないと思うけど。","ENG":"Says the woman who pierced a C.O.'s core with one bullet...","TWN":"這好像不是能一發穿透侵蝕體核心的人該說的話。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"야, 깡통. 저 녀석들… 안전한 거 맞아?","JPN":"おい、ポンコツ。あいつら……本当に安全なのか？","ENG":"Hey, tin can. Are those people... actually safe?","TWN":"喂，鐵桶。這些傢伙……真的安全嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그걸 저한테 물어보셔도…….","JPN":"私に聞かれましても……","ENG":"Asking me won't–","TWN":"你問我也……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"안심하세요, 키이라님.","JPN":"ご安心ください、キーラ様。","ENG":"Rest assured, Miss Kiera.","TWN":"別擔心，琪伊拉。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저희 플로라 메이드가 모시는 주인님은 여러분이 최고 관리자라 부르는 분.","JPN":"私たちフローラメイドが仕えるご主人様は、皆さんが最高管理者とお呼びしているお方。","ENG":"The Master we Flora Maids serve is the one you call the Supreme Administrator.","TWN":"我們芙蘿拉女僕侍奉的主人，就是你們稱為最高管理者的那一位。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님의 뜻은 곧 저희의 뜻이기에, 의심은 거두셔도 됩니다.","JPN":"ご主人様の意志は私たちの意志ですので、疑う必要などありません。","ENG":"His will is our will. You may trust us.","TWN":"主人的意志就是我們的意志，這點無需懷疑。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"사람들을 구해줬다니까, 일단 적이 아니라는 건 믿겠어.","JPN":"住民を助けたらしいから、とりあえず敵じゃないってことは信じるよ。","ENG":"All right... you saved people, so I'll believe you're not the enemy.","TWN":"既然你們救了人，我暫時相信你們不是敵人。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"하지만 왜 섬을 떠나지 않는 거야?","JPN":"でも、なんで島から出ないんだ？","ENG":"But why aren't you leaving the island?","TWN":"但你們為什麼不離開這座島？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"지금 바다는 아비규환이라고.","JPN":"今、海はまさに阿鼻叫喚の状態なんだ。","ENG":"The sea is chaos right now.","TWN":"現在海上亂成一團耶。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L37_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"직할 도시는 파도처럼 밀려 들어오는 침식체를 처리하느라 애를 먹고 있어.","JPN":"直轄都市は波のように押し寄せてくる侵食体を処理するだけでも手一杯。","ENG":"Front Bay's choking under waves of C.O.s.","TWN":"直轄城市正為湧入的侵蝕體頭痛不已。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나 같은 고위험 범죄자를 사법 거래로 풀어줄 정도로 말이야.","JPN":"あたしみたいな高危険度の犯罪者を司法取引で解放してくれるほどにな。","ENG":"To the point they let a high-risk criminal like me walk out on a judicial deal.","TWN":"甚至都願意透過司法交易讓我這種高危險罪犯出來協助。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그만큼 도시를 지키고 싶은 마음이라는 거겠죠.","JPN":"そうしてでも都市を守りたいということでしょう。","ENG":"If anything, it shows just how much they wanted to protect their home.","TWN":"那大概就是他們想守護城市的心意吧。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"사람의 목숨을, 자신의 자유를 포기하면서까지 지켜야 할 이유가 있는 거야?","JPN":"人の命とか自分の自由を放棄してまで守る理由なんてあるのか？","ENG":"Is there really something worth protecting, even at the cost of people's lives and their freedom?","TWN":"妳有理由犧牲自己的自由，只為了為了保護大家的性命嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"고향은 고향일 뿐이잖아.","JPN":"ただの故郷だろ。","ENG":"A home is just a home.","TWN":"故鄉就是故鄉不是嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"키이라씨는 프론트 베이에서 나고 자라셨나요?","JPN":"キーラさんは、フロントベイ出身なんですか？","ENG":"Kiera... were you born and raised here in Front Bay?","TWN":"琪伊拉是在前灣出生長大的嗎？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"맞아. 비록 부모가 누군지는 모르지만, 난 프론트 베이에서 나고 자랐어.","JPN":"そう。親は誰なのか知らないけど、あたしはフロントベイで生まれ育ったさ。","ENG":"Yeah. I don't know who my parents are, but I was born and raised in Front Bay.","TWN":"沒錯。雖然不知道父母是誰，但我是在前灣出生長大的。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"사람들은 관리국에 의해 자유롭게 바다로 나갈 권리를 빼앗긴 채 살아가는 것을 봐왔지.","JPN":"都市のみんなが、自由に海に出る権利を管理局に奪われたまま、生きる姿を見てきた。","ENG":"I've watched people live with their right to sail freely stripped away by the Administration.","TWN":"我親眼看著人們因為管理局失去自由出海的權利。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"누군가는 직업을 잃었고, 누군가는 허가 없이 바다에 나갔다는 것만으로 범죄자가 되었어.","JPN":"誰かは職を失い、誰かは許可なく海に出たっていうだけで犯罪者になった。","ENG":"Some lost their jobs. Some became criminals just for going out to sea without permission.","TWN":"有人失去工作，有人僅僅因為未經允許出海就成了罪犯。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"게다가 관리국은 사람들을 통제하기 위해 외지인을 들였고, 그게 사람들을 더 갈라지게 했어.","JPN":"それに管理局はみんなを統制するためによそ者を受け入たから、それがみんなの仲を一層悪くしたんだ。","ENG":"And the Administration brought in outsiders to control everyone, which only made people more divided.","TWN":"而且管理局為了控制人們引進外地人，卻只讓居民之間更加分裂。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그렇기 때문에 관리국으로부터 고향을 되돌려주고 싶은 거야.","JPN":"だからあたしは管理局から故郷を取り戻してやりたいんだ。","ENG":"That's why I want to take my home back from them.","TWN":"所以我才想從管理局手中奪回我們的故鄉。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그 이상도, 그 이하도 아니라고.","JPN":"それ以上でも、以下でもない。","ENG":"Nothing more, nothing less.","TWN":"不多也不少，就只是這樣。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"맞는 말이에요.","JPN":"一理ありますね。","ENG":"Yes, you're right.","TWN":"妳說得沒錯。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"생명의 가치는 그 어떤 것보다 낮을 수 없으니까요.","JPN":"命の価値は、何より大切なものですから。","ENG":"Life is more precious than anything.","TWN":"生命的價值永遠不能低於任何東西。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"하지만 키이라.","JPN":"でもね、キーラさん。","ENG":"But Kiera.","TWN":"但是琪伊拉，"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"때론 사람은 상식적으로 이해할 수 없는 행동을 하기도 해요.","JPN":"時に人は、常識では理解できない行動をしたりもします。","ENG":"Sometimes people act in ways that defy reason.","TWN":"有時候人也會做出無法用常理解釋的行動。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"예를 들면, 내가 평생을 바쳐 번 돈으로 산 집,","JPN":"例えば、自分が一生稼いだお金で買った家、","ENG":"Like the home I worked my whole life to build,","TWN":"例如，用一生積蓄買下的房子、"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"내 유년 시절을 바친 고향,","JPN":"自分の幼い時代を捧げた故郷、","ENG":"the hometown that holds every memory of my childhood...","TWN":"寄託童年時光的故鄉、"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"혹은 그냥 이곳의 분위기, 냄새, 사람들…… 그런 것들이 좋아서 자유를 내던지는 사람들이 많죠.","JPN":"あるいはただここの雰囲気、匂い、人々……そんなものが好きで自由を犠牲にする人もいるのです。","ENG":"or even just the feel of this place, its scent, its voices... Some people give up their freedom for things like that.","TWN":"又或者只是不知為何喜歡這裡的氛圍、味道、以及這裡的人們……也有很多因為這些理由而放棄自由的人。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"20년 전, 갑작스레 일어난 검은 범람에 휘말린 우리 섬을 구해준…….","JPN":"20年前、突然と発生した黒い氾濫に巻き込まれた私たちの島を助けてくれた……","ENG":"Just like the Avery Pirates did...","TWN":"20年前，拯救這座被突如其來的黑色洪災襲擊的島嶼的……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"에이버리 해적단처럼 말이에요.","JPN":"エイバリー海賊団のように。","ENG":"when they saved our island twenty years ago, during the Black Flood.","TWN":"就是艾維利海盜團。"},"stage":{"bg":"FRONTBAY_03","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"에이버리 해적단이 여기까지 왔었다고?","JPN":"エイバリー海賊団がここまで来てたのか？","ENG":"The Avery Pirates came all the way out here?","TWN":"艾維利海盜團來過這裡？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그럼요. 아주 멋진 분들이었어요.","JPN":"ええ。とても素晴らしい方々でした。","ENG":"They did. They were truly wonderful people.","TWN":"當然，他們是非常帥氣的人。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"오늘만 살아가는 이들에게 내일을 보여주고 싶다는 말, 저는 아직도 기억하고 있거든요.","JPN":"今日だけを生きている者たちに明日を見せてあげたいという言葉、私はまだ忘れていません。","ENG":"The words, \\"To show tomorrow to those who only live in the moment,\\" I still remember clearly.","TWN":"我到現在都還記得想讓只活在今天的人也能看見明天這句話。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"오늘만 살아가는 이들에게… 내일을 보여주고 싶다…….","JPN":"今日だけを生きている者たちに……明日を見せてあげたい……","ENG":"To show tomorrow... to those who only live in the moment...","TWN":"讓只活在今天的人……看見明天……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"후후, 그리고 키이라 씨를 보다 보면 그때 봤던 부함장님이 생각나요.","JPN":"ふふ、それにキーラさんを見ていると、あの時お会いした副艦長が思い出されるわ。","ENG":"Fufu... And when I look at Kiera, she reminds me of the first mate I met back then.","TWN":"呵呵，每次看著妳，都會讓我想起那時看到的副船長。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"그분도 당신과 비슷하지만 다른 말씀을 하셨거든요.","JPN":"あの方も、あなたの言葉と近いけれど、少し違うことをおっしゃっていました。","ENG":"She said something a little like what you said but in her own way.","TWN":"她也說過一句有點類似但又不太一樣的話。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_MOE","text":{"KOREA":"사람의 목숨을, 자신의 자유를 포기하면서까지 지켜야 할 것이 있는 법이라고.","JPN":"人の命や自分の自由を放棄してでも、守らなければいけないものはあるんだって。","ENG":"That there are things worth protecting even if it costs your freedom... even if it costs your life.","TWN":"人有時候會為了某些東西，付出自己的生命與自由去守護。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONEMOTHER_NPC_NULL_MOE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나는 잘… 모르겠어.","JPN":"あたしにはよく……わかんない。","ENG":"I don't... really get it.","TWN":"我……不明白。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"모르시는 게 잘못된 것이 아닙니다. 키이라 님.","JPN":"わからないということは間違いではありません、キーラ様。","ENG":"There is nothing wrong with not knowing, Miss Kiera.","TWN":"不明白並不是錯，琪伊拉。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"저 역시… 모실 분을 찾기 전까지는 키이라 님처럼 방황하는 몸이었으니까요.","JPN":"私もまた……仕えるべき方を見つけるまではキーラ様のように彷徨っていましたから。","ENG":"I, too... wandered aimlessly until I found the one I wished to serve.","TWN":"在找到該侍奉的人之前……我也和你一樣到處漂泊。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 주인님을 만난 순간…….","JPN":"ですが、ご主人様に出会った瞬間……","ENG":"And when I met Master...","TWN":"但在遇見主人那一刻……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"모에나 님께서 말한 <color=#ffd34c>이해할 수 없는 행동</color>이 무엇인지 알게 되었습니다.","JPN":"モエナ様がおっしゃる、<color=#ffd34c>理解できない行動</color>がどういうものかわかりました。","ENG":"I understood what Miss Moena meant by <color=#ffd34c>actions beyond understanding.</color>","TWN":"我明白了莫埃娜說的那種<color=#ffd34c>無法理解的行動</color>是什麼意思。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그 사람만 바라보게 돼서?","JPN":"その人だけを見つめるようになったから？","ENG":"Because you only look at him?","TWN":"只因為只看到那個人？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"후훗, 그럴지도 모르겠군요.","JPN":"ふふっ、そうかもしれません。","ENG":"Fufu, perhaps.","TWN":"呵呵，也許吧。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님을 향한 관심은 메이드의 필수 덕목이니까요.","JPN":"ご主人様への関心はメイドに必須な心得ですから。","ENG":"Attention toward one's master is a maid's essential virtue, after all.","TWN":"關注主人，是女僕最基本的素養。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"방황하는 널 받아준 사람이라서?","JPN":"彷徨ってるお前を受け入れてくれた人だから？","ENG":"Because he accepted you while you were lost?","TWN":"因為他接納了漂泊的你？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그것 또한 맞는 말씀입니다. 저에게 편히 쉴 수 있는 공간을 마련해 주셨으니.","JPN":"それも正解です。私に落ち着いて休める場所を作ってくださったのですから。","ENG":"That, too. He gave me a place to rest.","TWN":"這也沒錯。他給了我能安心休息的空間。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그리고 무엇보다…….","JPN":"それに、なにより……","ENG":"And more than anything...","TWN":"而且最重要的是……"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님은 저를 기다린다고 말씀하셨거든요.","JPN":"ご主人様は私の帰りを待つと言ってくださいました。","ENG":"He told me he would wait for me.","TWN":"主人曾說過他會等我。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L1_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"아줌마, 내 부모님은 왜 안 계신 걸까?","JPN":"おばさん、どうしてあたしにはお母さんも、お父さんもいないの？","ENG":"Auntie Mary... why don't I have parents?","TWN":"阿姨，為什麼我的父母不在？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"……네 부모님은 프론트 베이를 구하기 위해 먼 길을 떠났단다.","JPN":"……あなたの両親は、フロントベイを救うために長い旅に出たのよ。","ENG":"...Your parents left on a long journey to save Front Bay.","TWN":"……你的父母為了拯救前灣踏上了遙遠旅程。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"프론트 베이의 바다에는 크라켄이라는 괴물이 잠들어 있어.","JPN":"フロントベイの海にはクラーケンという化け物が眠っていてね。","ENG":"A monster called Kraken sleeps beneath our waters.","TWN":"有隻叫克拉肯的怪物在前灣的海中沉睡著。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"그 괴물이 일어나 몸부림 칠 때마다 검은 범람이 발생해 우리 고향을 파괴하거든.","JPN":"その化け物が目覚めて体を動かすたびに、黒い氾濫が発生して私たちの故郷を破壊していたの。","ENG":"Whenever it wakes and thrashes, the Black Flood destroys our home.","TWN":"每當那隻怪物醒來翻騰時，就會引發黑色洪災，破壞我們的故鄉。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"그래서 키이라의 부모님은 그 크라켄이 푹 잘 수 있도록 자장가를 불러주고 있단다.","JPN":"だからキーラの両親はそのクラーケンがぐっすり眠れるように子守歌を歌っているのよ。","ENG":"So your parents are singing it a lullaby so it can sleep soundly.","TWN":"所以你的父母為了讓克拉肯能熟睡，正在唱著搖籃曲呢。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"우웅… 나도 데려가면 좋았을 텐데.","JPN":"うーん……あたしも連れて行ってくれたら良かったのに。","ENG":"Aww... They could've taken me, too.","TWN":"嗚……如果能帶我去就好了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"나도 노래를 잘 불렀다면 데려가지 않았을까?","JPN":"あたしも歌が上手だったら連れて行ったかな？","ENG":"If I were better at singing, maybe they would've taken me along?","TWN":"如果我也很會唱歌，就能一起去了嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"후훗, 그곳엔 크라켄 말고도 무서운 괴물들이 잔뜩이라 위험하거든.","JPN":"ふふっ、そこにはクラーケンの他にも怖い化け物がいっぱいいて危険な所だからね。","ENG":"Fufu. That place is full of scary monsters besides Kraken. Much too dangerous.","TWN":"呵呵，那裡除了克拉肯還有很多可怕的怪物，很危險呢。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_YOUNG","text":{"KOREA":"그럼 내가… 어떻게 하면 부모님이 보러 와줄까?","JPN":"じゃあ、あたしが……どうしたら2人が会いに来てくれるかな？","ENG":"Then... how do I make them come back to see me?","TWN":"那我……要怎麼做父母才會回來看我？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"프론트 베이가 안전해진다면.","JPN":"フロントベイが安全になったら。","ENG":"If Front Bay becomes safe...","TWN":"如果前灣變得安全。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"바다가 더 이상 위험하지 않고 누구나 자유롭게 나갈 수 있다면.","JPN":"海がもう危険ではなくなって、誰もが自由に海へ出られるようになったら。","ENG":"If the sea stops being dangerous, and anyone can go freely...","TWN":"如果大海不再危險，任何人都能自由出入，"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"그래. 그때쯤이라면…….","JPN":"そう。その頃になれば……","ENG":"Yes. By then...","TWN":"沒錯。到那時候……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"READ_NPC_MARY_SILHOUETTE","text":{"KOREA":"너도 똑바로 마주할 수 있겠지.","JPN":"あなたもちゃんと向き合うことができるだろうね。","ENG":"You'll be able to face them properly.","TWN":"妳也能好好看著他們了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_YOUNG","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"선의의 거짓말은 당연하게도 내 유일한 목표이자 지향점으로 만들었다.","JPN":"善意の嘘は、自然にあたしの唯一の目標であり動機となった。","ENG":"A white lie, of course. But one that became my only goal, my only direction.","TWN":"善意的謊言，理所當然地成為我唯一的目標與信念。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"강해지고, 강해져서, 프론트 베이에 영원한 평화를 가져온다면 부모님이 돌아오지 않을까.","JPN":"強くなり、また強くなって、フロントベイに永遠の平和をもたらすことができれば両親が帰ってくるんじゃないか。","ENG":"If I could grow strong enough to bring lasting peace to Front Bay, maybe my parents would return.","TWN":"只要變強、再變得更強、為前灣帶來永遠的和平……父母說不定就會回來了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"narration","speaker":null,"text":{"KOREA":"어릴 적의 그 작은 목표를 위해 나는 부단히도 노력했지만.","JPN":"幼い頃のその純粋な目標のため、あたしは絶えず努力した。","ENG":"For that tiny childhood dream, I worked and worked and worked.","TWN":"為了那小小的目標，我拼命努力。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"narration","speaker":null,"text":{"KOREA":"날 기다려주는 이는 아무도 없었다.","JPN":"でも、あたしを待ってくれる人は誰もいなかった。","ENG":"But no one ever waited for me.","TWN":"但卻沒有人等我。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이런 나라도… 기다려줄 사람이 있을까?","JPN":"こんなあたしでも……待ってくれる人がいるかな？","ENG":"Would someone... wait for someone like me?","TWN":"像我這樣的人……也會有人等我嗎？"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"물론입니다.","JPN":"もちろんです。","ENG":"Of course.","TWN":"當然囉。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"피로 뒤범벅된 제 모습마저 포용해 주신 주인님이 계신 것처럼요.","JPN":"血まみれの私の姿でさえ包み込んでくださった、ご主人様のような方がきっと。","ENG":"Just as my master embraced even the blood-soaked version of me.","TWN":"就像主人包容滿身鮮血的我一樣。"},"stage":{"bg":"VILLAGE1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"}]`);export{e as default};